// Format the form submission as a standard FOI request
const form = $input.item.json;

// Generate case reference
const year = new Date().getFullYear();
const randomNum = Math.floor(Math.random() * 9000) + 1000;
const caseRef = `FOI-${year}-${randomNum}`;

// Get submission date
const receivedDate = new Date();
const receivedDateStr = receivedDate.toLocaleDateString('en-GB', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Calculate 20-working-day deadline
function addWorkingDays(startDate, days) {
  let count = 0;
  let current = new Date(startDate);
  const bankHolidays = [
    '2025-12-25', '2025-12-26', '2026-01-01', '2026-04-03', '2026-04-06',
    '2026-05-04', '2026-05-25', '2026-08-31', '2026-12-25', '2026-12-28'
  ];
  while (count < days) {
    current.setDate(current.getDate() + 1);
    const dayOfWeek = current.getDay();
    const dateStr = current.toISOString().split('T')[0];
    if (dayOfWeek !== 0 && dayOfWeek !== 6 && !bankHolidays.includes(dateStr)) {
      count++;
    }
  }
  return current;
}

const deadlineDate = addWorkingDays(receivedDate, 20);
const deadlineDateStr = deadlineDate.toLocaleDateString('en-GB', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Extract form fields
const senderName = form.full_name || form['Full Name'] || 'Unknown';
const senderEmail = form.email_address || form['Email Address'] || '';
const organisation = form.organisation || form['Organisation (if applicable)'] || '';
const requestDetails = form.request_details || form['Your FOI Request'] || '';
const preferredFormat = form.preferred_format || form['Preferred Format'] || 'Electronic (email/PDF)';
const previousRef = form.reference_to_previous || form['Reference to Previous Request (if applicable)'] || '';

// Format as standard email-style body for consistent processing
const formattedBody = `FOI REQUEST SUBMITTED VIA WEB FORM

Submitted by: ${senderName}${organisation ? ' (' + organisation + ')' : ''}
Email: ${senderEmail}
Preferred format: ${preferredFormat}
${previousRef ? 'Reference to previous request: ' + previousRef : ''}

REQUEST:
${requestDetails}`;

return [{
  json: {
    caseRef,
    senderEmail,
    senderName,
    organisation,
    subject: `FOI Request (Web Form) — ${requestDetails.substring(0, 80)}${requestDetails.length > 80 ? '...' : ''}`,
    body: formattedBody,
    requestDetails,
    preferredFormat,
    previousRef,
    receivedDate: receivedDate.toISOString(),
    receivedDateStr,
    deadlineDate: deadlineDate.toISOString(),
    deadlineDateStr,
    source: 'WEB_FORM'
  }
}];

