// Parse the Claude API response for form submissions
const response = $input.item.json;
const prevData = $('Code: Format as FOI Request').item.json;

let responseText = '';
if (response.content && response.content[0] && response.content[0].text) {
  responseText = response.content[0].text;
} else {
  throw new Error('Unexpected API response: ' + JSON.stringify(response));
}

let analysis;
try {
  const jsonMatch = responseText.match(/```json\s*([\s\S]*?)\s*```/) ||
                    responseText.match(/```\s*([\s\S]*?)\s*```/);
  const jsonStr = jsonMatch ? jsonMatch[1] : responseText;
  analysis = JSON.parse(jsonStr.trim());
} catch (e) {
  // Fallback acknowledgement
  const fallbackAck = `Dear ${prevData.senderName},

Thank you for your Freedom of Information request submitted via our online form.

We have registered your request with case reference ${prevData.caseRef}.

We will respond within 20 working days, by ${prevData.deadlineDateStr}.

If you have any queries, please contact us at foi@westshire.icb.nhs.uk quoting your case reference.

Freedom of Information Team
NHS Westshire Integrated Care Board
Westshire House, 12 Cathedral Quarter, Westminster-upon-Avon WS1 2AB
foi@westshire.icb.nhs.uk`;

  analysis = {
    request_type: 'UNCLEAR',
    disclosure_decision: 'PENDING_MANUAL_REVIEW',
    draft_acknowledgement: fallbackAck,
    draft_response: 'MANUAL REVIEW REQUIRED.',
    internal_notes: `Form submission parsing failed. Raw: ${responseText.substring(0, 500)}`,
    escalation_required: true,
    potential_exemptions: []
  };
}

return [{
  json: {
    ...prevData,
    analysis,
    claudeUsage: response.usage || {}
  }
}];

